// src/index.ts
var DEFAULT_OUTPUT_FILE = "index.html";
var DEFAULT_RPC_BASE_URL = "https://<baseURL>";
function resolveOutFile(input) {
  const outFile = getOptionString(
    input.options,
    "outFile",
    DEFAULT_OUTPUT_FILE
  );
  const trimmedOutFile = outFile.trim();
  const finalOutFile = trimmedOutFile.length > 0 ? trimmedOutFile : DEFAULT_OUTPUT_FILE;
  assert(
    finalOutFile.endsWith(".html"),
    `Invalid outFile "${finalOutFile}". The output file must end with .html`
  );
  return finalOutFile;
}
__name(resolveOutFile, "resolveOutFile");
function resolveRpcBaseUrl(input) {
  const rpcBaseUrl = getOptionString(
    input.options,
    "rpcBaseUrl",
    DEFAULT_RPC_BASE_URL
  );
  const trimmedRpcBaseUrl = rpcBaseUrl.trim();
  return trimmedRpcBaseUrl.length > 0 ? trimmedRpcBaseUrl : DEFAULT_RPC_BASE_URL;
}
__name(resolveRpcBaseUrl, "resolveRpcBaseUrl");
var generate = definePlugin((input) => {
  input.ir.entryPoint = "";
  const outFile = resolveOutFile(input);
  const ir = escapeScriptTag(JSON.stringify(anonymizeIr(input.ir)));
  let rpcBaseUrl = escapeScriptTag(JSON.stringify(resolveRpcBaseUrl(input)));
  rpcBaseUrl = rpcBaseUrl.replace(/\/+$/, "");
  let html = build_default.replace(
    "window.__vdl_ir = {};",
    `window.__vdl_ir = ${ir};`
  );
  html = html.replace(
    'window.__vdl_rpc_base_url = "https://<baseURL>";',
    `window.__vdl_rpc_base_url = ${rpcBaseUrl};`
  );
  return {
    files: [
      {
        path: outFile,
        content: html
      }
    ]
  };
});
